// Set up secret key for hashing passwords
const secretKey = 'your_secret_key_here';

function hashPassword(password) {
  return crypto.createHmac('sha256', secretKey).update(password).digest('hex');
}

function storeUserInCookie(res, username, passwordHash) {
  const cookieData = JSON.stringify({ username, passwordHash });
  res.cookie('remember_me', cookieData, { maxAge: 30 * 24 * 60 * 60 * 1000 }); // 30 days
}

